import React from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import { Toaster } from 'react-hot-toast';

// Pages
import Register from './pages/Register';
import Login from './pages/Login';
import Dashboard from './pages/Dashboard';
import ProjectSubmit from './pages/ProjectSubmit';
import JudgePanel from './pages/JudgePanel';
import AdminDashboard from './pages/AdminDashboard';
import Winners from './pages/Winners';

// Components
import Navbar from './components/Navbar';
import PrivateRoute from './components/PrivateRoute';

function App() {
  return (
    <Router>
      <div className="min-h-screen bg-gray-50">
        <Navbar />
        <Toaster position="top-right" />
        
        <Routes>
          <Route path="/" element={<Navigate to="/register" />} />
          <Route path="/register" element={<Register />} />
          <Route path="/login" element={<Login />} />
          
          <Route path="/dashboard" element={
            <PrivateRoute>
              <Dashboard />
            </PrivateRoute>
          } />
          
          <Route path="/submit-project" element={
            <PrivateRoute>
              <ProjectSubmit />
            </PrivateRoute>
          } />
          
          {/* Judge Panel - Public (accessed via QR code) */}
          <Route path="/judge/:code" element={<JudgePanel />} />
          
          {/* Admin Routes */}
          <Route path="/admin" element={<AdminDashboard />} />
          <Route path="/admin/winners/:grade" element={<Winners />} />
        </Routes>
      </div>
    </Router>
  );
}

export default App;
